// SECURITY: Validate Fireflies HMAC signature
// Fireflies sends x-hub-signature as SHA-256 HMAC of the raw body
const crypto = require('crypto');
const secret = $env.FIREFLIES_WEBHOOK_SECRET;
const sig = $input.first().headers['x-hub-signature'];
const body = JSON.stringify($input.first().body);
const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(body).digest('hex');
if (sig !== expected) {
  throw new Error('Invalid Fireflies webhook signature — possible spoofed request');
}
// Extract meetingId and pass it forward
const meetingId = $input.first().body.meetingId;
if (!meetingId) throw new Error('Webhook body missing meetingId');
return [{ json: { meetingId } }];

// Build a clean speaker-labelled transcript string from the sentences array
// Cap at ~60,000 chars to stay within Claude's context window safely
const transcript = $input.first().json.data.transcript;
const sentences = transcript.sentences || [];
const lines = sentences.map(s => `${s.speaker_name}: ${s.text}`);
let transcriptText = lines.join('\n');
if (transcriptText.length > 60000) {
  transcriptText = transcriptText.slice(0, 60000) + '\n\n[TRANSCRIPT TRUNCATED — TOO LONG]';
}
return [{
  json: {
    meetingId: $('Validate Signature').first().json.meetingId,
    meetingTitle: transcript.title || 'Untitled Meeting',
    meetingDate: transcript.date || '',
    meetingDuration: transcript.duration || 0,
    organizerEmail: transcript.organizer_email || '',
    participants: transcript.participants || [],
    firefliesSummary: transcript.summary?.overview || '',
    transcriptText
  }
}];

