// Parse and validate Agent 1 JSON output
// Strict check: ensure all required fields are present
const raw = $input.first().json.text || $input.first().json.content || $input.first().json.message?.content || '';
let parsed;
try {
  // Strip markdown code fences if model wrapped in them
  const cleaned = raw.replace(/^```json\n?/,'').replace(/^```\n?/,'').replace(/\n?```$/,'').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Agent 1 returned invalid JSON. Raw output: ' + raw.slice(0, 500));
}
// Validate required fields
const required = ['meeting_meta','prospect','pain_points','objections','action_items','overall_sentiment'];
const missing = required.filter(k => !(k in parsed));
if (missing.length) {
  throw new Error('Agent 1 JSON missing required fields: ' + missing.join(', '));
}
const validSentiments = ['positive','neutral','negative','mixed'];
if (!validSentiments.includes(parsed.overall_sentiment)) {
  parsed.overall_sentiment = 'neutral'; // safe fallback
}
// Attach original transcript context for Agent 2
parsed._firefliesSummary = $('Format Transcript').first().json.firefliesSummary;
return [{ json: parsed }];

