// Parse Agent 2 output and merge both agent payloads into final templateData
const agent2Raw = $input.first().json.text || $input.first().json.content || $input.first().json.message?.content || '';
let agent2;
try {
  const cleaned = agent2Raw.replace(/^```json\n?/,'').replace(/^```\n?/,'').replace(/\n?```$/,'').trim();
  agent2 = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Agent 2 returned invalid JSON. Raw: ' + agent2Raw.slice(0, 500));
}
// Merge Agent 1 extraction with Agent 2 narrative
const agent1 = $('Validate & Parse JSON').first().json;
const merged = {
  ...agent1,
  executive_summary: agent2.executive_summary || '',
  strategic_assessment: agent2.strategic_assessment || '',
  recommended_approach: agent2.recommended_approach || ''
};
// Clean internal key
delete merged._firefliesSummary;
return [{ json: merged }];

// Inject templateData into the HTML template using simple string replacement
// The template uses {{key}} and Handlebars-style helpers which we resolve here
const data = $input.first().json;

// Helpers
const esc = s => (s == null ? '' : String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'));
const sentimentClass = s => 'sentiment-' + (s || 'neutral');

// Render attendees list
const attendeesHtml = (data.meeting_meta?.attendees || []).map(a => `<li>${esc(a)}</li>`).join('');

// Render pain points
const painPointsHtml = (data.pain_points || []).map(p => `<li>${esc(p)}</li>`).join('');

// Render objections
const objectionsHtml = data.objections?.length
  ? `<ul>${data.objections.map(o => `<li>${esc(o)}</li>`).join('')}</ul>`
  : '<p class="muted">No objections recorded.</p>';

// Render key quotes
const quotesSlide = data.key_quotes?.length
  ? `<section class="slide">
      <p class="kicker">Voice of Prospect</p>
      <h2>Key Quotes</h2>
      <div style="display: grid; gap: var(--space-md);">
        ${data.key_quotes.map(q => `<blockquote class="quote-block">&ldquo;${esc(q)}&rdquo;</blockquote>`).join('')}
      </div>
    </section>`
  : '';

// Render action items table rows
const actionItemsContent = data.action_items?.length
  ? `<div class="table-wrap"><table><thead><tr><th>Owner</th><th>Action</th><th>Due Date</th></tr></thead><tbody>${
      data.action_items.map(ai => `<tr><td>${esc(ai.owner)}</td><td>${esc(ai.action)}</td><td>${ai.due_date ? esc(ai.due_date) : '<span class="muted">TBD</span>'}</td></tr>`).join('')
    }</tbody></table></div>`
  : '<div class="card"><p class="muted">No explicit action items recorded.</p></div>';

// Render next step line
const nextStepHtml = data.next_steps
  ? `<p style="margin-top: var(--space-md); font-weight: 700; color: var(--brand-primary);">Agreed Next Step: ${esc(data.next_steps)}</p>`
  : '';

// Read the base HTML template (must be stored as a file or hardcoded string)
// For n8n: the template is read from a previous node or passed as env variable.
// Here we assume the template HTML is available as $env.CALL_ANALYSIS_TEMPLATE
// or you read it from a Read Binary File node output.
let html = $env.CALL_ANALYSIS_TEMPLATE_HTML || '';

// Simple replacements
const replacements = {
  '{{meeting_meta.title}}': esc(data.meeting_meta?.title),
  '{{meeting_meta.date}}': esc(data.meeting_meta?.date),
  '{{meeting_meta.duration_minutes}}': esc(String(data.meeting_meta?.duration_minutes || '')),
  '{{meeting_meta.organizer}}': esc(data.meeting_meta?.organizer),
  '{{overall_sentiment}}': esc(data.overall_sentiment),
  'sentiment-{{overall_sentiment}}': sentimentClass(data.overall_sentiment),
  '{{prospect.company_name}}': esc(data.prospect?.company_name || '—'),
  '{{prospect.contact_name}}': esc(data.prospect?.contact_name || '—'),
  '{{prospect.role}}': esc(data.prospect?.role || '—'),
  '{{prospect.industry}}': esc(data.prospect?.industry || '—'),
  '{{prospect.company_size}}': esc(data.prospect?.company_size || '—'),
  '{{executive_summary}}': esc(data.executive_summary),
  '{{strategic_assessment}}': esc(data.strategic_assessment),
  '{{recommended_approach}}': esc(data.recommended_approach),
};

for (const [k, v] of Object.entries(replacements)) {
  html = html.replace(new RegExp(k.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'), v);
}

// Inject dynamic blocks
html = html.replace('<!--ATTENDEES_LIST-->', attendeesHtml);
html = html.replace('<!--PAIN_POINTS_LIST-->', painPointsHtml);
html = html.replace('<!--OBJECTIONS_BLOCK-->', objectionsHtml);
html = html.replace('<!--QUOTES_SLIDE-->', quotesSlide);
html = html.replace('<!--ACTION_ITEMS_CONTENT-->', actionItemsContent);
html = html.replace('<!--NEXT_STEP_HTML-->', nextStepHtml);

// Signal fields with null handling
const currentSolution = data.current_solution ? esc(data.current_solution) : '<span class="signal-null">Not mentioned</span>';
const budgetSignals = data.budget_signals ? esc(data.budget_signals) : '<span class="signal-null">Not mentioned</span>';
const timelineSignals = data.timeline_signals ? esc(data.timeline_signals) : '<span class="signal-null">Not mentioned</span>';
html = html.replace('<!--CURRENT_SOLUTION-->', currentSolution);
html = html.replace('<!--BUDGET_SIGNALS-->', budgetSignals);
html = html.replace('<!--TIMELINE_SIGNALS-->', timelineSignals);

return [{ json: { html, meetingTitle: data.meeting_meta?.title || 'call-analysis' } }];

